const item = $input.first().json;
const DEFAULT_EMAILS = ['shivamskr151@gmail.com', 'muskan.betla@gmail.com'];
const BATCH_RUN_ID = `batch_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`;

const parseList = (raw) => {
  if (Array.isArray(raw)) return raw.map((e) => String(e).trim()).filter(Boolean);
  const str = String(raw || '').trim();
  if (!str) return [];
  return str.split(/[,;|]/).map((e) => e.trim()).filter(Boolean);
};

const normalizeResumePath = (raw) => {
  let p = String(raw || '').trim();
  if (!p) return '';
  if (p.startsWith('./files/')) p = p.replace('./files', '/files');
  if (p.startsWith('files/resumes/')) p = `/files/resumes/${p.split('files/resumes/')[1]}`;
  if (!p.startsWith('/files/')) {
    if (p.startsWith('resumes/')) p = `/files/${p}`;
    else p = `/files/resumes/${p.replace(/^\/+/, '')}`;
  }
  return p;
};

const normalizeJobTitles = (raw, root) => {
  const list = Array.isArray(raw) ? raw : parseList(raw);
  return list.map((entry) => {
    if (typeof entry === 'string') {
      return {
        title: entry.trim(),
        required_skills: root.required_skills || [],
        preferred_skills: root.preferred_skills || [],
        min_experience_years: root.min_experience_years || 0,
        job_description: root.job_description || '',
      };
    }
    if (entry && typeof entry === 'object') {
      return {
        title: String(entry.title || entry.job_title || '').trim(),
        required_skills: entry.required_skills || root.required_skills || [],
        preferred_skills: entry.preferred_skills || root.preferred_skills || [],
        min_experience_years: Number(entry.min_experience_years ?? root.min_experience_years ?? 0),
        job_description: String(entry.job_description || root.job_description || '').trim(),
      };
    }
    return null;
  }).filter((j) => j && j.title);
};

const root = item;
let emails = parseList(root.candidate_emails);
if (!emails.length) emails = parseList(root.candidate_email);
if (!emails.length) emails = [...DEFAULT_EMAILS];

const jobTitles = normalizeJobTitles(root.job_titles || root.jobs || [], root);
if (String(root.job_title || '').trim() && !jobTitles.length) {
  jobTitles.push(...normalizeJobTitles([{ title: root.job_title }], root));
}

const buildResumeEntry = (entry, idx) => {
  if (typeof entry === 'string') {
    const p = normalizeResumePath(entry);
    const base = p.split('/').pop() || `resume_${idx + 1}.pdf`;
    const name = base.replace(/\.(pdf|txt)$/i, '').replace(/[_-]+/g, ' ').trim();
    return { candidate_name: name, candidate_email: '', resume_file_path: p, resume_filename: base };
  }
  const p = normalizeResumePath(entry.resume_file_path || entry.path || entry.file || '');
  const base = p.split('/').pop() || entry.resume_filename || `resume_${idx + 1}.pdf`;
  const name = entry.candidate_name || base.replace(/\.(pdf|txt)$/i, '').replace(/[_-]+/g, ' ').trim();
  return {
    candidate_name: name,
    candidate_email: entry.candidate_email || entry.email || '',
    candidate_emails: entry.candidate_emails || [],
    resume_file_path: p,
    resume_filename: entry.resume_filename || base,
    resume_text: entry.resume_text || '',
    resume_base64: entry.resume_base64 || '',
    resume_mime_type: entry.resume_mime_type || '',
  };
};

let resumeEntries = [];
if (Array.isArray(root.resumes) && root.resumes.length) {
  resumeEntries = root.resumes.map(buildResumeEntry);
} else if (Array.isArray(root.resume_file_paths) && root.resume_file_paths.length) {
  resumeEntries = root.resume_file_paths.map(buildResumeEntry);
} else if (root.scan_resumes_folder) {
  if (!root.allow_batch_scan) {
    throw new Error('Batch folder scan is disabled. Send a PDF directly or use /scan <filename>.');
  }
  const fs = require('fs');
  const dir = String(root.resumes_folder || '/files/resumes').trim();
  const files = fs.readdirSync(dir)
    .filter((f) => /\.(pdf|txt)$/i.test(f) && !/^resume_\d+_/i.test(f))
    .sort();
  resumeEntries = files.map((f) => buildResumeEntry(`${dir}/${f}`));
} else if (normalizeResumePath(root.resume_file_path || root.existing_resume_file || '')) {
  resumeEntries = [buildResumeEntry({
    candidate_name: root.candidate_name,
    candidate_email: root.candidate_email,
    candidate_emails: root.candidate_emails,
    resume_file_path: root.resume_file_path,
    resume_filename: root.resume_filename,
    resume_text: root.resume_text,
    resume_base64: root.resume_base64,
    resume_mime_type: root.resume_mime_type,
  })];
} else if (String(root.resume_text || '').trim() || String(root.resume_base64 || '').trim()) {
  resumeEntries = [{
    candidate_name: root.candidate_name || 'Candidate',
    candidate_email: root.candidate_email || '',
    candidate_emails: root.candidate_emails || [],
    resume_filename: root.resume_filename || 'resume.txt',
    resume_text: root.resume_text || '',
    resume_base64: root.resume_base64 || '',
    resume_mime_type: root.resume_mime_type || 'text/plain',
  }];
}

if (!resumeEntries.length) {
  throw new Error('Provide resumes, resume_file_paths, resume_file_path, resume_text, or set scan_resumes_folder=true');
}

if (!root.allow_batch_scan && resumeEntries.length > 1) {
  throw new Error('Only one resume per request. Send a PDF directly or use /scan <filename>.');
}

const useResumeJobTitle = root.use_resume_job_title !== false && jobTitles.length === 0;
if (!useResumeJobTitle && !jobTitles.length) {
  throw new Error('Provide job_titles array or set use_resume_job_title=true');
}

const shared = {
  ...root,
  batch_run_id: BATCH_RUN_ID,
  candidate_emails: emails,
  candidate_email: emails.join(', '),
  job_titles: jobTitles,
  job_title: jobTitles[0]?.title || root.job_title || '',
  use_resume_job_title: useResumeJobTitle,
  match_all_job_titles: jobTitles.length > 0,
  batch_size: resumeEntries.length,
};

if (!String(shared.job_description || '').trim()) {
  shared.job_description = jobTitles.length
    ? 'Evaluate candidate fit against all open roles and assign the best match.'
    : 'Evaluate candidate fit for the exact job title found on the resume.';
}


return resumeEntries.map((entry, i) => {
  let entryEmails = parseList(entry.candidate_emails);
  if (!entryEmails.length) entryEmails = parseList(entry.candidate_email);
  if (!entryEmails.length) entryEmails = emails;
  const hasPath = Boolean(normalizeResumePath(entry.resume_file_path || ''));
  return {
    json: {
      ...shared,
      ...entry,
      candidate_emails: entryEmails,
      candidate_email: entryEmails.join(', '),
      resume_file_path: hasPath ? normalizeResumePath(entry.resume_file_path) : entry.resume_file_path,
      resume_index: i + 1,
      run_id: `resume_${Date.now()}_${Math.random().toString(16).slice(2, 8)}_${i}`,
      processed_at: new Date().toISOString(),
    },
  };
});

const item = $json;
const RESUME_DIR = '/files/resumes';
const fn = String(item.resume_filename || '').toLowerCase();
let ext = fn.endsWith('.pdf') ? 'pdf' : fn.endsWith('.txt') ? 'txt' : 'txt';
if (item.resume_mime_type === 'application/pdf') ext = 'pdf';
let buffer;
if (String(item.resume_text || '').trim()) buffer = Buffer.from(String(item.resume_text), 'utf8');
else {
  const b64 = String(item.resume_base64 || '').trim();
  if (!b64) throw new Error('No resume content to save');
  buffer = Buffer.from(b64, 'base64');
}
const mimeType = ext === 'pdf' ? 'application/pdf' : 'text/plain';
const fileName = `${item.run_id}.${ext}`;
const resume_file_path = `${RESUME_DIR}/${fileName}`;
return { json: { ...item, resume_file_path, resume_file_ext: ext, resume_storage: { directory: RESUME_DIR, saved_file: resume_file_path, host_folder: './files/resumes', host_file: `./files/resumes/${fileName}` } }, binary: { data: { data: buffer.toString('base64'), mimeType, fileName } } };

const ctx = $('Restore Meta After Read').item.json;
const row = $json;
const text = String(row.text || row.data || row.content || '').trim();
if (!text) throw new Error('No text extracted from saved PDF file');
return { json: { ...ctx, extracted_resume_text: text, extraction_source: 'saved_pdf_file', analyzed_from: ctx.resume_file_path } };

const ctx = $('Restore Meta After Read').item.json;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const text = buffer.toString('utf8').trim();
if (!text) throw new Error('Saved TXT file is empty');
return { json: { ...ctx, extracted_resume_text: text, extraction_source: 'saved_txt_file', analyzed_from: ctx.resume_file_path } };

const item = $json;
const text = String(item.extracted_resume_text || '');

const emailMatch = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const phoneMatch = text.match(/(\+?\d[\d\s().-]{7,}\d)/);
const yearsMatch = text.match(/(\d+)\+?\s*years?/i);

const lines = text.split(/\n+/).map((x) => x.trim()).filter(Boolean);
const summary = lines.slice(0, 5).join(' ').slice(0, 600);

return { json: {
    ...item,
    structured_resume: {
      candidate_name: item.candidate_name || null,
      candidate_email: item.candidate_email || (emailMatch ? emailMatch[0] : null),
      candidate_phone: phoneMatch ? phoneMatch[0] : null,
      inferred_experience_years: yearsMatch ? Number(yearsMatch[1]) : null,
      resume_summary: summary,
      raw_resume_text: text,
      structured_at: new Date().toISOString()
    }
  }
};

function cleanKey(key) {
  return String(key || '').trim().replace(/^Bearer\s+/i, '');
}
function isOpenRouterKey(key) {
  return /^sk-or-/i.test(cleanKey(key));
}
function chatCompletionsUrl(apiKey) {
  return isOpenRouterKey(apiKey)
    ? 'https://openrouter.ai/api/v1/chat/completions'
    : 'https://api.openai.com/v1/chat/completions';
}
function normalizeModel(model, apiKey) {
  const m = String(model || $env.OPENAI_MODEL || 'gpt-4o-mini').trim();
  if (isOpenRouterKey(apiKey)) {
    return m.includes('/') ? m : 'openai/' + m.replace(/^openai\//, '');
  }
  return m.replace(/^openai\//, '');
}
async function getAiApiKey(payload) {
  let key = cleanKey(payload?.openai_api_key || payload?.openrouter_api_key);
  if (!key) key = cleanKey($env.OPENAI_API_KEY || $env.OPENROUTER_API_KEY || '');
  if (!key) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      key = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!key) throw new Error('Missing OPENAI_API_KEY. Set in .env or pass openai_api_key in the webhook body.');
  return key;
}

const item = $json;
const apiKey = await getAiApiKey.call(this, item);
const model = normalizeModel(item.openai_model || item.openrouter_model, apiKey);
const jobTitle = String(item.job_title || item.resume_job_title || '').trim();
if (!jobTitle) throw new Error('Missing job title for analysis');

const systemPrompt = 'You are an ATS assistant. Analyze the candidate against the assigned job title (best match from open roles or resume title). Return strict JSON with keys: ats_score (0-100), matched_skills (array), missing_skills (array), extracted_skills (array), experience_analysis { total_years, relevant_years, level, strengths, gaps }, job_match_score (0-100), title_alignment { exact_title, aligned (boolean), reason }, recommendation { verdict, confidence, reason }, report_summary.';
const userPrompt = `Assigned Job Title: ${jobTitle}
Other titles on resume: ${(item.resume_all_job_titles || []).join(' | ')}
Job Description context: ${item.job_description || 'N/A'}
Required Skills: ${(item.required_skills || []).join(', ') || 'Infer from resume and title'}
Preferred Skills: ${(item.preferred_skills || []).join(', ') || 'None'}
Minimum Experience Years: ${item.min_experience_years || 0}

Score how well this resume fits the role: "${jobTitle}".

Resume Text:
${item.structured_resume?.raw_resume_text || ''}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: chatCompletionsUrl(apiKey),
  headers: {
    Authorization: `Bearer ${apiKey}`,
    'Content-Type': 'application/json',
    'X-Title': 'Resume Analysis Agent'
  },
  body: {
    model,
    temperature: 0.2,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  },
  json: true,
  timeout: 60000
});

const raw = response.choices?.[0]?.message?.content;
const analysis = typeof raw === 'string' ? JSON.parse(raw) : raw;

return { json: {
    ...item,
    ai_analysis: {
      ...analysis,
      model: response.model || model,
      analyzed_at: new Date().toISOString()
    }
  }
};

const item = $json;
return { json: {
    ...item,
    ats_result: {
      score: Number(item.ai_analysis?.ats_score || 0),
      matched_skills: item.ai_analysis?.matched_skills || [],
      missing_skills: item.ai_analysis?.missing_skills || []
    }
  }
};

const item = $json;
return { json: {
    ...item,
    skill_extraction: {
      extracted_skills: item.ai_analysis?.extracted_skills || [],
      matched_skills: item.ai_analysis?.matched_skills || [],
      missing_skills: item.ai_analysis?.missing_skills || []
    }
  }
};

const item = $json;
return { json: {
    ...item,
    experience_result: item.ai_analysis?.experience_analysis || {}
  }
};

const item = $json;
const aiJobMatch = Number(item.ai_analysis?.job_match_score || 0);
const ats = Number(item.ats_result?.score || 0);
const experienceYears = Number(item.experience_result?.relevant_years || item.experience_result?.total_years || 0);
const experienceRatio = item.min_experience_years > 0 ? Math.min(100, (experienceYears / item.min_experience_years) * 100) : 100;
const weightedMatch = Math.round((aiJobMatch * 0.5) + (ats * 0.3) + (experienceRatio * 0.2));

return { json: {
    ...item,
    job_match: {
      ai_job_match_score: aiJobMatch,
      weighted_match_score: weightedMatch,
      experience_ratio_score: Math.round(experienceRatio),
      matched_skills_count: (item.skill_extraction?.matched_skills || []).length,
      missing_skills_count: (item.skill_extraction?.missing_skills || []).length
    }
  }
};

const item = $json;
const score = Number(item.job_match?.weighted_match_score || 0);
let recommendation = 'Reject';
if (score >= 80) recommendation = 'Strong Shortlist';
else if (score >= 65) recommendation = 'Shortlist';
else if (score >= 50) recommendation = 'Review';

return { json: {
    ...item,
    recommendation: {
      label: item.ai_analysis?.recommendation?.verdict || recommendation,
      confidence: Number(item.ai_analysis?.recommendation?.confidence || 0),
      reason: item.ai_analysis?.recommendation?.reason || 'Generated from ATS, skill, and experience signals.'
    }
  }
};

const item = $json;
const token = String(item.telegram_bot_token || '').trim();
const chatId = String(item.telegram_chat_id || '').trim();
let telegram_delivery = { status: 'skipped', reason: 'disabled_or_missing_credentials' };

if (item.notify_telegram && token && chatId) {
  const text = String(item.report_text || '').trim();
  if (!text) {
    telegram_delivery = { status: 'skipped', reason: 'empty_message' };
  } else {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://api.telegram.org/bot${token}/sendMessage`,
        body: { chat_id: chatId, text },
        json: true,
        timeout: 30000
      });
      if (!resp?.ok) {
        throw new Error(resp?.description || 'Telegram API returned ok:false');
      }
      telegram_delivery = {
        status: 'sent',
        message_id: resp.result?.message_id || null,
        chat_id: chatId
      };
    } catch (err) {
      telegram_delivery = { status: 'failed', error: err?.message || 'request_failed' };
    }
  }
}

return { json: { ...item, telegram_delivery } };

const item = $json;
const recipients = (item.candidate_emails || []).length
  ? item.candidate_emails
  : String(item.candidate_email || '').split(/[,;]/).map((e) => e.trim()).filter(Boolean);
const to = recipients.join(', ');
const recommended = item.job_title_ranking?.categorized_under || item.job_title || item.resume_job_title || 'Unknown';
const matchScore = item.job_match?.weighted_match_score ?? item.job_title_ranking?.best_match?.match_score ?? 'n/a';
const reasoning = item.job_title_ranking?.best_match?.reasoning || item.recommendation?.reason || '';
const summary = item.ai_analysis?.report_summary || item.report?.ai_summary || '';
const allMatches = (item.job_title_ranking?.all_matches || [])
  .slice(0, 5)
  .map((m) => `<li><strong>${m.title}</strong>: ${m.match_score}/100 — ${m.reasoning || ''}</li>`)
  .join('');

const html = `<div style="font-family:Arial,sans-serif;max-width:720px;color:#111827;">
  <h2 style="color:#1d4ed8;">Resume Analysis Report</h2>
  <p>Hi ${item.candidate_name || 'Candidate'},</p>
  <p>Your resume has been analyzed against our open roles.</p>
  <table style="border-collapse:collapse;width:100%;margin:16px 0;">
    <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Candidate</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${item.candidate_name || 'Unknown'}</td></tr>
    <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Recommended Job Title</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${recommended}</td></tr>
    <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Match Score</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${matchScore}</td></tr>
    <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>ATS Score</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${item.ats_result?.score ?? 'n/a'}</td></tr>
    <tr><td style="padding:8px;border:1px solid #e5e7eb;"><strong>Recommendation</strong></td><td style="padding:8px;border:1px solid #e5e7eb;">${item.recommendation?.label || 'n/a'}</td></tr>
  </table>
  <h3>Reasoning</h3>
  <p>${reasoning}</p>
  <h3>Resume Analysis Summary</h3>
  <p>${summary}</p>
  ${allMatches ? `<h3>All Role Matches</h3><ul>${allMatches}</ul>` : ''}
  <p style="color:#6b7280;font-size:13px;">Run ID: ${item.run_id}${item.batch_run_id ? ` | Batch: ${item.batch_run_id}` : ''}</p>
  <p>Regards,<br/>Recruitment AI Assistant</p>
</div>`;

return { json: {
    ...item,
    email_outbound: {
      from: item.sender_email || 'information@variphi.com',
      to,
      subject: `Resume Analysis — ${recommended} — ${item.candidate_name || 'Candidate'}`,
      html,
    },
  },
};

const item = $input.first().json;
const batch = item.batch_summary || {};
const isBatch = (batch.total_processed || 0) > 1;

return [{
  json: {
    success: true,
    batch_run_id: item.batch_run_id || item.run_id,
    total_processed: batch.total_processed || 1,
    categories: batch.categories || [item.job_title_ranking?.categorized_under || item.job_title].filter(Boolean),
    categorized_candidates: batch.categorized_candidates || {
      [item.job_title_ranking?.categorized_under || item.job_title || 'Uncategorized']: [{
        candidate_name: item.candidate_name,
        recommended_job_title: item.job_title,
        match_score: item.job_match?.weighted_match_score ?? null,
        recommendation: item.recommendation?.label || null,
      }],
    },
    candidates: isBatch
      ? Object.values(batch.categorized_candidates || {}).flat()
      : [{
          run_id: item.run_id,
          candidate_name: item.candidate_name,
          candidate_email: item.candidate_email || null,
          recommended_job_title: item.job_title_ranking?.categorized_under || item.job_title,
          match_score: item.job_match?.weighted_match_score ?? item.job_title_ranking?.best_match?.match_score ?? null,
          reasoning: item.job_title_ranking?.best_match?.reasoning || item.recommendation?.reason || null,
          recommendation: item.recommendation || {},
          ats_score: item.ats_result?.score ?? null,
          report: item.report || {},
        }],
    run_id: item.run_id,
    candidate_name: item.candidate_name,
    job_title_ranking: item.job_title_ranking || null,
    recommendation: item.recommendation || {},
    report: item.report || {},
    delivery: {
      telegram: item.telegram_delivery || null,
      email_attempted: Boolean(item.notify_email),
      email_sent: Boolean(item.email_outbound?.to),
    },
    completed_at: new Date().toISOString(),
  },
}];

const item = $json;
const path = String(item.resume_file_path || '').trim();
if (!path) throw new Error('resume_file_path is required for existing file mode');

const base = path.split('/').pop() || 'resume.pdf';
const ext = base.toLowerCase().endsWith('.pdf') ? 'pdf' : 'txt';

