      host_file: `./files/resumes/${base}`
    }
  }
};

let meta = {};
try { const ex = $('Use Existing Resume File').item; if (ex?.json?.resume_file_path) meta = ex.json; } catch (e) {}
if (!meta.resume_file_path) meta = $('After Write Resume Meta').item.json;
return { json: meta, binary: $binary };

function cleanKey(key) {
  return String(key || '').trim().replace(/^Bearer\s+/i, '');
}
