  let key = cleanKey(payload?.openai_api_key || payload?.openrouter_api_key);
  if (!key) key = cleanKey($env.OPENAI_API_KEY || $env.OPENROUTER_API_KEY || '');
  if (!key) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
