    } catch (e) {}
  }
  if (!key) throw new Error('Missing OPENAI_API_KEY. Set in .env or pass openai_api_key in the webhook body.');
  return key;
}

const item = $json;
const text = String(item.structured_resume?.raw_resume_text || item.extracted_resume_text || '').trim();
if (!text) throw new Error('No resume text available for job title extraction');

const apiKey = await getAiApiKey.call(this, item);
const model = normalizeModel(item.openai_model || item.openrouter_model, apiKey);
const systemPrompt = 'You extract job titles from resumes. Return strict JSON with keys: current_job_title (string, exact title from most recent/current role), headline (string or null), all_job_titles (array of exact titles from work history, most recent first). Use exact wording from the resume.';
const userPrompt = `Extract the exact job title(s) from this resume. Prefer the most recent/current role as current_job_title.\n\nResume:\n${text}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: chatCompletionsUrl(apiKey),
  headers: {
    Authorization: `Bearer ${apiKey}`,
    'Content-Type': 'application/json',
    'X-Title': 'Resume Analysis Agent'
  },
  body: {
    model,
    temperature: 0.1,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  },
  json: true,
  timeout: 60000
});

const raw = response.choices?.[0]?.message?.content;
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
const current = String(parsed.current_job_title || parsed.headline || '').trim();
if (!current) throw new Error('Could not extract job title from resume');

const allTitles = Array.isArray(parsed.all_job_titles) ? parsed.all_job_titles.map((t) => String(t).trim()).filter(Boolean) : [];
const job_title = current;
const job_titles = [job_title];

return { json: {
    ...item,
    resume_job_title: job_title,
    resume_all_job_titles: allTitles.length ? allTitles : [job_title],
    job_title,
    job_titles,
    matched_against: 'resume_job_title',
    job_title_extraction: {
      current_job_title: job_title,
      headline: parsed.headline || null,
      all_job_titles: allTitles.length ? allTitles : [job_title],
      extracted_at: new Date().toISOString()
    }
  }
};

const item = $json;
if (item.use_resume_job_title === false) {
  const title = String(item.job_title || '').trim();
  if (!title) throw new Error('job_title is required when use_resume_job_title=false');
  return { json: { ...item, job_title: title, job_titles: [title], matched_against: 'payload_job_title' } };
}
return { json: item };

function cleanKey(key) {
  return String(key || '').trim().replace(/^Bearer\s+/i, '');
}
function isOpenRouterKey(key) {
  return /^sk-or-/i.test(cleanKey(key));
}
function chatCompletionsUrl(apiKey) {
  return isOpenRouterKey(apiKey)
    ? 'https://openrouter.ai/api/v1/chat/completions'
    : 'https://api.openai.com/v1/chat/completions';
}
function normalizeModel(model, apiKey) {
  const m = String(model || $env.OPENAI_MODEL || 'gpt-4o-mini').trim();
  if (isOpenRouterKey(apiKey)) {
    return m.includes('/') ? m : 'openai/' + m.replace(/^openai\//, '');
  }
  return m.replace(/^openai\//, '');
}
async function getAiApiKey(payload) {
  let key = cleanKey(payload?.openai_api_key || payload?.openrouter_api_key);
  if (!key) key = cleanKey($env.OPENAI_API_KEY || $env.OPENROUTER_API_KEY || '');
  if (!key) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      key = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!key) throw new Error('Missing OPENAI_API_KEY. Set in .env or pass openai_api_key in the webhook body.');
  return key;
}

const item = $json;
const jobTitles = item.job_titles || [];
if (!jobTitles.length) throw new Error('job_titles required for ranking');

const apiKey = await getAiApiKey.call(this, item);
const model = normalizeModel(item.openai_model || item.openrouter_model, apiKey);
const resumeText = item.structured_resume?.raw_resume_text || item.extracted_resume_text || '';

const openings = jobTitles.map((j, i) => `[${i + 1}] ${j.title}
Required: ${(j.required_skills || []).join(', ') || 'Infer from resume'}
Preferred: ${(j.preferred_skills || []).join(', ') || 'None'}
Min experience: ${j.min_experience_years || 0} years
Description: ${j.job_description || 'N/A'}`).join('\n\n');

const systemPrompt = 'You are an expert technical recruiter. Compare the candidate resume against EVERY job opening listed. Pick the single best-fitting role. Return strict JSON with keys: candidate_name (string), best_match { title, match_score (0-100), reasoning }, all_matches (array of { title, match_score, reasoning, matched_skills, gaps }), categorized_under (string, equals best_match.title). Sort all_matches by match_score descending.';
const userPrompt = `Candidate label: ${item.candidate_name || 'Unknown'}
Resume file: ${item.resume_filename || item.resume_file_path || 'n/a'}

JOB OPENINGS:
${openings}

RESUME:
${resumeText}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: chatCompletionsUrl(apiKey),
  headers: {
    Authorization: `Bearer ${apiKey}`,
    'Content-Type': 'application/json',
    'X-Title': 'Resume Analysis Agent',
  },
  body: {
    model,
    temperature: 0.2,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt },
    ],
  },
  json: true,
  timeout: 90000,
});

const raw = response.choices?.[0]?.message?.content;
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
const best = parsed.best_match || {};
const bestTitle = String(best.title || parsed.categorized_under || jobTitles[0].title).trim();
const matchedJob = jobTitles.find((j) => j.title.toLowerCase() === bestTitle.toLowerCase()) || jobTitles[0];

return { json: {
    ...item,
    candidate_name: parsed.candidate_name || item.candidate_name,
    job_title: bestTitle,
    job_title_ranking: {
      best_match: best,
      all_matches: parsed.all_matches || [],
      categorized_under: parsed.categorized_under || bestTitle,
      ranked_at: new Date().toISOString(),
    },
    matched_against: 'best_job_title',
    resume_job_title: bestTitle,
    resume_all_job_titles: (parsed.all_matches || []).map((m) => m.title),
    required_skills: matchedJob.required_skills || item.required_skills || [],
    preferred_skills: matchedJob.preferred_skills || item.preferred_skills || [],
    min_experience_years: matchedJob.min_experience_years ?? item.min_experience_years ?? 0,
    job_description: matchedJob.job_description || item.job_description || '',
  },
};

const items = $input.all().map((i) => i.json);
const byJobTitle = {};

for (const item of items) {
  const cat = item.job_title_ranking?.categorized_under || item.job_title || 'Uncategorized';
  if (!byJobTitle[cat]) byJobTitle[cat] = [];
  byJobTitle[cat].push({
    run_id: item.run_id,
    candidate_name: item.candidate_name,
    candidate_email: item.candidate_email,
    resume_file: item.resume_filename || item.resume_file_path,
    recommended_job_title: item.job_title,
    match_score: item.job_match?.weighted_match_score ?? item.job_title_ranking?.best_match?.match_score ?? null,
    ranking_reasoning: item.job_title_ranking?.best_match?.reasoning || null,
    recommendation: item.recommendation?.label || null,
    recommendation_reason: item.recommendation?.reason || null,
    ats_score: item.ats_result?.score ?? null,
    summary: item.ai_analysis?.report_summary || item.report?.ai_summary || '',
    all_title_matches: item.job_title_ranking?.all_matches || [],
    report: item.report || {},
    delivery: {
      email: item.email_outbound ? 'prepared' : 'skipped',
      telegram: item.telegram_delivery || null,
    },
  });
}

const first = items[0] || {};
const categoryLines = Object.entries(byJobTitle).map(([title, cands]) =>
  `${title} (${cands.length}): ${cands.map((c) => c.candidate_name).join(', ')}`
).join('\n');

return [{
  json: {
    ...first,
    batch_summary: {
      batch_run_id: first.batch_run_id,
      total_processed: items.length,
      categories: Object.keys(byJobTitle),
      categorized_candidates: byJobTitle,
      summary_text: categoryLines,
    },
    all_candidates: items,
    report_text: [
      'Batch Resume Analysis Summary',
      `Processed: ${items.length} resume(s)`,
      '',
      categoryLines,
    ].join('\n'),
  },
}];
